//-------------------------------------------------------------------------
// 추가값 DataList의 column값 변경시 호출하는 함수.
//-------------------------------------------------------------------------  
scwin.ds_additionalValue_oncelldatachange = function (info) {
  let rowIndex = info.rowIndex;
  let colId = info.colID;
  if (colId == "clntNo") {} else if (colId == "additionalKndCd") {
    let kndCd = ds_additionalValue.getCellData(rowIndex, "additionalKndCd");
    if (kndCd == "1" || kndCd == "2" || kndCd == "3") {
      ds_additionalValue.setCellData(rowIndex, "gubun", "1");
    } else if (kndCd == "4" || kndCd == "5") {
      ds_additionalValue.setCellData(rowIndex, "gubun", "2");
    }
  }
};

