/** ***********************************************************************
 *  ETC 해당 프로그램에서 사용되는 함수 정의 START
 ************************************************************************ */
scwin.f_PopUpGrid = function (_options = {}) {
  // pCallback, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, pW, pH, pTop, pLeft, pExistTF, pAllSearchTF, 
  // pWtitleSearch, pNoDataCloseTF, tmpDataSet, pCodeObj, pNameObj
  const options = Object.assign({
    gubun: _options.gubun || "clntPopup",
    pCode: _options.clntNo || "",
    pName: _options.clntNm || "",
    pWinCloseTF: _options.pWinCloseTF || 'T',
    pDispCnt: _options.pDispCnt || '5',
    pTitle: _options.pTitle || "거래처코드,거래처명",
    pWidth: _options.pWidth || "130,300",
    pHidden: _options.pHidden || "3,4,5,6,7,8,9,10",
    pWhere: _options.pWhere || null // "100"
    ,
    pW: _options.pW || "500",
    pH: _options.pH || "500",
    pTop: _options.pTop || null,
    pLeft: _options.pLeft || null,
    pExistTF: _options.pExistTF || null,
    pAllSearchTF: _options.pAllSearchTF || 'F',
    pWtitleSearch: _options.pWtitleSearch || null //"거래처 팝업,거래처코드,거래처명"
    ,
    pNoDataCloseTF: _options.pNoDataCloseTF || "F"
  }, _options);
  switch (options.gubun) {
    case "clntPopup":
      // 거래처 팝업
      udc_clntNo.cfCommonPopUp(scwin.clntPopupCallBackFn, options.pCode, options.pName, options.pWinCloseTF, options.pDispCnt, options.pTitle, options.pWidth, options.pHidden, options.pWhere, options.pW, options.pH, options.pTop, options.pLeft, options.pExistTF, options.pAllSearchTF, options.pWtitleSearch, options.pNoDataCloseTF); // 거래처			
      break;
  }
};

//-------------------------------------------------------------------------
// 그리드에 footer를 설정하는 함수 
//-------------------------------------------------------------------------         
scwin.setGridFooter = function (masterList = []) {
  if (masterList.length == 0) return;
  const lastDay = $c.date.getLastDateOfMonth($p, ed_stdYm.getValue());
  const footerMap = {};
  const beforeKeyInfo = ["rsltsAmt", "planAmt", "sumAmt"];
  const beforeMap = {};
  masterList.forEach(master => {
    for (let i = 1; i <= lastDay; i++) {
      if (!footerMap[`amt${i}d`]) {
        footerMap[`amt${i}d`] = 0;
      }
      footerMap[`amt${i}d`] += (master["additionalKndCd"] == "1" ? 1 : -1) * Number(master[`amt${i}d`]);
    }
    beforeKeyInfo.map(key => {
      if (!beforeMap[key]) {
        beforeMap[key] = 0;
      }
      beforeMap[key] += (master["additionalKndCd"] == "1" ? 1 : -1) * Number(master[key]);
    });
  });
  const stdRamt = Number(ed_ramt.getValue() || 0);
  for (let i = lastDay; i >= 1; i--) {
    let amtSum = 0;
    for (let j = 1; j < i; j++) {
      amtSum += footerMap[`amt${j}d`];
    }
    footerMap[`amt${i}d`] += amtSum + stdRamt;
  }
  for (let i = lastDay; i >= 1; i--) {
    gr_masterList.setFooterData(`amt${i}d`, footerMap[`amt${i}d`]);
  }
  beforeKeyInfo.map(key => {
    gr_masterList.setFooterData(key, stdRamt + beforeMap[key]);
  });
};
